// ── Name→Religion model v4 (joint elector+relation scoring, suffix fallback) ─
function classifyReligion(name, relationName = "", SCORES = NAME_SCORES) {
  // Normalise: uppercase, strip trailing punctuation (handles "Md." → "MD")
  const _tok = (s) => String(s).toUpperCase().trim().split(/\s+/).map(t => t.replace(/[.,\-']+$/,"")).filter(t=>t.length>=2);

  // Score a single name string against SCORES; returns {rel,conf} or {rel:null}
  const _scoreTok = (nameStr) => {
    if (!nameStr) return { rel: null, conf: 0 };
    const tokens = _tok(nameStr);
    const vals = tokens.filter(t => t in SCORES).map(t => SCORES[t]);
    if (!vals.length) return { rel: null, conf: 0 };
    const muslimV = vals.filter(v => v >= 0.70);
    const hinduV  = vals.filter(v => v <= 0.30);
    const maxM = Math.max(...muslimV, 0);
    const minH = Math.min(...hinduV, 1);
    const strongM = vals.filter(v => v >= 0.85);
    if (strongM.length > 0 && hinduV.length < muslimV.length)
      return { rel: "Muslim", conf: +Math.max(...strongM).toFixed(3) };
    if (maxM >= 0.75 && minH >= 0.25)
      return { rel: "Muslim", conf: +maxM.toFixed(3) };
    if (minH <= 0.25 && muslimV.length === 0)
      return { rel: "Hindu", conf: +(1 - minH).toFixed(3) };
    const avg = vals.reduce((a, b) => a + b, 0) / vals.length;
    if (avg >= 0.60) return { rel: "Muslim", conf: +avg.toFixed(3) };
    if (avg <= 0.40) return { rel: "Hindu",  conf: +(1-avg).toFixed(3) };
    return { rel: "Uncertain", conf: +(Math.abs(avg - 0.5) * 2).toFixed(3) };
  };

  // Score both elector + relation tokens JOINTLY (pool all known tokens together)
  // Used as fallback when individual scoring leaves both uncertain/null
  const _scoreJoint = (n, rn) => {
    const toksN  = _tok(n).filter(t => t in SCORES).map(t => SCORES[t]);
    const toksR  = _tok(rn).filter(t => t in SCORES).map(t => SCORES[t]);
    const vals   = [...toksN, ...toksR];
    if (!vals.length) return { rel: null, conf: 0 };
    const muslimV = vals.filter(v => v >= 0.70);
    const hinduV  = vals.filter(v => v <= 0.30);
    const strongM = vals.filter(v => v >= 0.85);
    const maxM = Math.max(...muslimV, 0);
    const minH = Math.min(...hinduV, 1);
    if (strongM.length > 0 && hinduV.length < muslimV.length)
      return { rel: "Muslim", conf: +Math.max(...strongM).toFixed(3), via: "joint" };
    if (maxM >= 0.75 && minH >= 0.25)
      return { rel: "Muslim", conf: +maxM.toFixed(3), via: "joint" };
    if (minH <= 0.25 && muslimV.length === 0)
      return { rel: "Hindu", conf: +(1-minH).toFixed(3), via: "joint" };
    const avg = vals.reduce((a,b)=>a+b,0)/vals.length;
    if (avg >= 0.60) return { rel: "Muslim", conf: +avg.toFixed(3), via: "joint" };
    if (avg <= 0.40) return { rel: "Hindu",  conf: +(1-avg).toFixed(3), via: "joint" };
    return { rel: "Uncertain", conf: +(Math.abs(avg-0.5)*2).toFixed(3), via: "joint-uncertain" };
  };

  const _scoreSuffix = (nameStr) => {
    if (!nameStr) return { rel: null, conf: 0 };
    const tokens = _tok(nameStr);
    for (const tok of tokens) {
      if (tok in SCORES) continue;
      for (let sl = 6; sl >= 4; sl--) {
        if (tok.length >= sl) {
          const suf = tok.slice(-sl);
          if (suf in MSUF && MSUF[suf] >= 0.90) return { rel: "Muslim", conf: +MSUF[suf].toFixed(3) };
          if (suf in HSUF && HSUF[suf] <= 0.10) return { rel: "Hindu",  conf: +(1-HSUF[suf]).toFixed(3) };
        }
      }
    }
    return { rel: null, conf: 0 };
  };

  // --- Decision chain ---
  const p = _scoreTok(name);
  // Strong signal from elector name alone → done
  if (p.rel && p.rel !== "Uncertain") return { ...p, via: "name" };

  const s = _scoreTok(relationName);
  // Strong signal from relation name alone → done
  if (s.rel && s.rel !== "Uncertain") return { ...s, via: "relation" };

  // Neither name alone is decisive → combine both as evidence pool
  const j = _scoreJoint(name, relationName);
  if (j.rel && j.rel !== "Uncertain" && j.rel !== null) return j;

  // Suffix fallback on elector name
  const sf = _scoreSuffix(name);
  if (sf.rel) return { ...sf, via: "suffix" };
  // Suffix fallback on relation name
  const sfr = _scoreSuffix(relationName);
  if (sfr.rel) return { ...sfr, via: "suffix-rel" };

  // Return best uncertain signal or unknown
  if (j.rel === "Uncertain") return j;
  if (p.rel === "Uncertain") return { ...p, via: "uncertain" };
  if (s.rel === "Uncertain") return { ...s, via: "uncertain-rel" };
  return { rel: "Unknown", conf: 0, via: "none" };
}


function getAgeGroup(age) {
  const a = parseInt(age);
  if (isNaN(a)) return "Unknown";
  if (a < 18)             return "<18";
  if (a <= 22)            return "18–22";
  if (a <= 30)            return "23–30";
  if (a <= 39)            return "31–39";
  if (a <= 44)            return "40–44★";
  if (a <= 60)            return "45–60";
  return "60+";
}
// ★ = self-mapped (were 18-20 in 2002, now 40-44)
function isSelfMapped(age) { const a=parseInt(age); return a>=40&&a<=44; }

